"""Reviewed concrete fallback tasks for every production curriculum topic.

The lesson engine normally supplies worked examples.  This bank is used only
when an example is a label or method description rather than a task a learner
can actually answer.  Every fallback has a concrete prompt, a short answer,
one-sentence reasoning and an independent verification idea.
"""
from __future__ import annotations

from dataclasses import dataclass


@dataclass(frozen=True)
class AssessmentTask:
    task: str
    final_answer: str
    reasoning: str
    verification: str


def T(task: str, answer: str, reasoning: str, verification: str) -> AssessmentTask:
    return AssessmentTask(task, answer, reasoning, verification)


