def get_topic_tasks(topic_id: str) -> tuple[AssessmentTask, AssessmentTask, AssessmentTask]:
    """Return the reviewed three-task fallback for a taxonomy topic."""

    try:
        return TOPIC_TASKS[str(topic_id)]
    except KeyError as exc:
        raise KeyError(f"No concrete assessment fallback for topic: {topic_id}") from exc
